# Debugging Race Conditions in Node.js Express with PostgreSQL Connection Pool

## Problem Description
Your Express app works fine under normal load but throws intermittent 500 errors when handling concurrent requests. The errors seem random and are difficult to reproduce consistently.

## Step 1: Reproduce the Issue

### 1.1 Create a Load Testing Script
```javascript
// load-test.js
const axios = require('axios');

async function loadTest() {
  const promises = [];
  const baseURL = 'http://localhost:3000';

  // Simulate 50 concurrent requests
  for (let i = 0; i < 50; i++) {
    promises.push(
      axios.post(`${baseURL}/api/users`, {
        name: `User ${i}`,
        email: `user${i}@example.com`
      }).catch(err => ({
        error: true,
        status: err.response?.status,
        message: err.message
      }))
    );
  }

  const results = await Promise.all(promises);
  const errors = results.filter(r => r.error);

  console.log(`Total requests: ${results.length}`);
  console.log(`Errors: ${errors.length}`);
  console.log('Error details:', errors);
}

loadTest();
```

### 1.2 Run the Test
```bash
node load-test.js
```

Expected output showing intermittent failures:
```
Total requests: 50
Errors: 7
Error details: [
  { error: true, status: 500, message: 'Request failed with status code 500' },
  // ... more errors
]
```

## Step 2: Add Comprehensive Logging

### 2.1 Enhanced Request Logging Middleware
```javascript
// middleware/logger.js
const { v4: uuidv4 } = require('uuid');

function requestLogger(req, res, next) {
  req.requestId = uuidv4();
  req.startTime = Date.now();

  console.log(`[${req.requestId}] ${req.method} ${req.path} - START`);

  // Log when response finishes
  res.on('finish', () => {
    const duration = Date.now() - req.startTime;
    console.log(`[${req.requestId}] ${req.method} ${req.path} - ${res.statusCode} (${duration}ms)`);
  });

  next();
}

module.exports = requestLogger;
```

### 2.2 Database Connection Pool Logging
```javascript
// db/pool.js
const { Pool } = require('pg');

const pool = new Pool({
  user: 'your_user',
  host: 'localhost',
  database: 'your_db',
  password: 'your_password',
  port: 5432,
  max: 10, // Maximum number of connections
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Add connection pool event listeners
pool.on('connect', (client) => {
  console.log(`[POOL] New client connected. Total: ${pool.totalCount}, Idle: ${pool.idleCount}`);
});

pool.on('acquire', (client) => {
  console.log(`[POOL] Client acquired. Total: ${pool.totalCount}, Idle: ${pool.idleCount}`);
});

pool.on('release', (client) => {
  console.log(`[POOL] Client released. Total: ${pool.totalCount}, Idle: ${pool.idleCount}`);
});

pool.on('error', (err, client) => {
  console.error('[POOL] Unexpected error on idle client', err);
});

module.exports = pool;
```

## Step 3: Identify the Problematic Code

### 3.1 Common Race Condition Pattern (PROBLEMATIC)
```javascript
// routes/users.js - PROBLEMATIC CODE
const express = require('express');
const pool = require('../db/pool');
const router = express.Router();

let userCounter = 0; // Shared state - PROBLEM!

router.post('/users', async (req, res) => {
  const client = await pool.connect();

  try {
    console.log(`[${req.requestId}] Got database client`);

    // Race condition: multiple requests can read/modify userCounter simultaneously
    userCounter++; // PROBLEM: Not atomic!
    const userId = userCounter;

    console.log(`[${req.requestId}] Assigned user ID: ${userId}`);

    // Simulate some processing time
    await new Promise(resolve => setTimeout(resolve, 100));

    const result = await client.query(
      'INSERT INTO users (id, name, email) VALUES ($1, $2, $3) RETURNING *',
      [userId, req.body.name, req.body.email]
    );

    res.json(result.rows[0]);
  } catch (error) {
    console.error(`[${req.requestId}] Database error:`, error.message);
    res.status(500).json({ error: 'Internal server error' });
  } finally {
    client.release();
    console.log(`[${req.requestId}] Released database client`);
  }
});

module.exports = router;
```

### 3.2 Run Load Test with Logging
```bash
node load-test.js
```

You'll see output like:
```
[abc-123] POST /api/users - START
[def-456] POST /api/users - START
[POOL] Client acquired. Total: 2, Idle: 8
[POOL] Client acquired. Total: 2, Idle: 7
[abc-123] Got database client
[def-456] Got database client
[abc-123] Assigned user ID: 1
[def-456] Assigned user ID: 1  // DUPLICATE ID!
[abc-123] Database error: duplicate key value violates unique constraint "users_pkey"
```

## Step 4: Analyze the Race Condition

### 4.1 Understanding the Problem
The race condition occurs because:

1. **Shared Mutable State**: `userCounter` is shared across all requests
2. **Non-Atomic Operations**: Reading and incrementing `userCounter` isn't atomic
3. **Timing Window**: Multiple requests can read the same value before any increment it

### 4.2 Visualizing the Race Condition
```
Time →
Request A: Read userCounter (0) → Increment (1) → Use ID 1
Request B:     Read userCounter (0) → Increment (1) → Use ID 1 ← CONFLICT!
```

## Step 5: Fix the Race Condition

### 5.1 Solution 1: Use Database Sequences (RECOMMENDED)
```javascript
// routes/users.js - FIXED VERSION
const express = require('express');
const pool = require('../db/pool');
const router = express.Router();

router.post('/users', async (req, res) => {
  const client = await pool.connect();

  try {
    console.log(`[${req.requestId}] Got database client`);

    // Let PostgreSQL handle ID generation atomically
    const result = await client.query(
      'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *',
      [req.body.name, req.body.email]
    );

    console.log(`[${req.requestId}] Created user with ID: ${result.rows[0].id}`);
    res.json(result.rows[0]);

  } catch (error) {
    console.error(`[${req.requestId}] Database error:`, error.message);
    res.status(500).json({ error: 'Internal server error' });
  } finally {
    client.release();
    console.log(`[${req.requestId}] Released database client`);
  }
});

module.exports = router;
```

### 5.2 Update Database Schema
```sql
-- Make sure your table uses auto-incrementing primary key
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
```

### 5.3 Solution 2: Use Atomic Operations (Alternative)
```javascript
// If you must use application-level counters
const cluster = require('cluster');

class AtomicCounter {
  constructor() {
    this.value = 0;
    this.lock = false;
  }

  async increment() {
    // Simple spinlock (not recommended for production)
    while (this.lock) {
      await new Promise(resolve => setImmediate(resolve));
    }

    this.lock = true;
    const result = ++this.value;
    this.lock = false;

    return result;
  }
}

const counter = new AtomicCounter();

router.post('/users', async (req, res) => {
  const client = await pool.connect();

  try {
    const userId = await counter.increment();

    const result = await client.query(
      'INSERT INTO users (id, name, email) VALUES ($1, $2, $3) RETURNING *',
      [userId, req.body.name, req.body.email]
    );

    res.json(result.rows[0]);
  } catch (error) {
    console.error(`[${req.requestId}] Database error:`, error.message);
    res.status(500).json({ error: 'Internal server error' });
  } finally {
    client.release();
  }
});
```

## Step 6: Add Connection Pool Monitoring

### 6.1 Pool Health Check Endpoint
```javascript
// routes/health.js
const express = require('express');
const pool = require('../db/pool');
const router = express.Router();

router.get('/health/db', async (req, res) => {
  try {
    const client = await pool.connect();
    const result = await client.query('SELECT NOW()');
    client.release();

    res.json({
      status: 'healthy',
      pool: {
        total: pool.totalCount,
        idle: pool.idleCount,
        waiting: pool.waitingCount
      },
      timestamp: result.rows[0].now
    });
  } catch (error) {
    res.status(500).json({
      status: 'unhealthy',
      error: error.message,
      pool: {
        total: pool.totalCount,
        idle: pool.idleCount,
        waiting: pool.waitingCount
      }
    });
  }
});

module.exports = router;
```

### 6.2 Connection Pool Timeout Handling
```javascript
// db/pool.js - Enhanced version
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT || 5432,
  max: 20, // Increased pool size
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 5000, // Increased timeout
  acquireTimeoutMillis: 10000, // Add acquire timeout
});

// Wrapper function with better error handling
async function queryWithRetry(text, params, retries = 3) {
  for (let i = 0; i < retries; i++) {
    try {
      const client = await pool.connect();
      try {
        const result = await client.query(text, params);
        return result;
      } finally {
        client.release();
      }
    } catch (error) {
      console.error(`Query attempt ${i + 1} failed:`, error.message);
      if (i === retries - 1) throw error;
      await new Promise(resolve => setTimeout(resolve, 100 * (i + 1)));
    }
  }
}

module.exports = { pool, queryWithRetry };
```

## Step 7: Verify the Fix

### 7.1 Run Load Test Again
```bash
node load-test.js
```

Expected output (no errors):
```
Total requests: 50
Errors: 0
```

### 7.2 Stress Test with Higher Concurrency
```javascript
