  const duration = Date.now() - start;

  const errors = results.filter(r => r.error);
  const successes = results.filter(r => !r.error);

  console.log(`Duration: ${duration}ms`);
  console.log(`Successful requests: ${successes.length}`);
  console.log(`Failed requests: ${errors.length}`);
  console.log(`Requests per second: ${(results.length / duration * 1000).toFixed(2)}`);
}

stressTest();
```

## Step 8: Prevention Strategies

### 8.1 Code Review Checklist
- [ ] No shared mutable state between requests
- [ ] Database operations use transactions where needed
- [ ] Connection pool limits are appropriate
- [ ] Proper error handling and connection cleanup
- [ ] Atomic operations for critical sections

### 8.2 Monitoring and Alerting
```javascript
// middleware/monitoring.js
const prometheus = require('prom-client');

const httpRequestDuration = new prometheus.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code']
});

const dbConnectionPoolGauge = new prometheus.Gauge({
  name: 'db_connection_pool_size',
  help: 'Database connection pool metrics',
  labelNames: ['type'] // 'total', 'idle', 'waiting'
});

function monitoringMiddleware(req, res, next) {
  const start = Date.now();

  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000;
    httpRequestDuration
      .labels(req.method, req.route?.path || req.path, res.statusCode)
      .observe(duration);
  });

  next();
}

module.exports = { monitoringMiddleware, dbConnectionPoolGauge };
```

This debugging walkthrough demonstrates how to identify, analyze, and fix race conditions in Node.js applications, with emphasis on proper connection pool management and atomic operations.

