// users/resolvers.ts
import { Resolvers } from './generated/graphql';
import DataLoader from 'dataloader';

const userLoader = new DataLoader(async (ids: readonly string[]) => {
  const users = await User.findByIds(ids);
  return ids.map(id => users.find(user => user.id === id));
});

const addressLoader = new DataLoader(async (userIds: readonly string[]) => {
  const addresses = await Address.findByUserIds(userIds);
  return userIds.map(userId => 
    addresses.filter(address => address.userId === userId)
  );
});

export const resolvers: Resolvers = {
  User: {
    __resolveReference: async (user: { id: string }) => {
      return userLoader.load(user.id);
    },

    profile: async (parent) => {
      return UserProfile.findByUserId(parent.id);
    },

    addresses: async (parent) => {
      return addressLoader.load(parent.id);
    },
  },

  Query: {
    me: async (_, __, { user }) => {
      if (!user) throw new Error('Not authenticated');
      return userLoader.load(user.id);
    },

    user: async (_, { id }, { user }) => {
      if (!user || user.role !== 'ADMIN') {
        throw new Error('Insufficient permissions');
      }
      return userLoader.load(id);
    },

    users: async (_, { limit, offset }, { user }) => {
      if (!user || user.role !== 'ADMIN') {
        throw new Error('Insufficient permissions');
      }
      return User.findPaginated({ limit, offset });
    },
  },

  Mutation: {
    updateProfile: async (_, { input }, { user }) => {
      if (!user) throw new Error('Not authenticated');
      return User.updateProfile(user.id, input);
    },

    addAddress: async (_, { input }, { user }) => {
      if (!user) throw new Error('Not authenticated');
      return Address.create({ ...input, userId: user.id });
    },
  },
};
