struct Node<K, V> {
    key: K,
    value: V,
    expires_at: Option<Instant>,
    prev: Option<Box<Node<K, V>>>,
    next: Option<Box<Node<K, V>>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V, ttl: Option<Duration>) -> Self {
        let expires_at = ttl.map(|duration| Instant::now() + duration);
        Self {
            key,
            value,
            expires_at,
            prev: None,
            next: None,
        }
    }

    fn is_expired(&self) -> bool {
        self.expires_at
            .map(|expires| Instant::now() > expires)
            .unwrap_or(false)
    }
}

// Cache entry for HashMap storage
#[derive(Debug, Clone)]
struct CacheEntry<V> {
    value: V,
    expires_at: Option<Instant>,
    access_count: usize,
}

impl<V> CacheEntry<V> {
    fn new(value: V, ttl: Option<Duration>) -> Self {
        let expires_at = ttl.map(|duration| Instant::now() + duration);
        Self {
            value,
            expires_at,
            access_count: 0,
        }
    }

    fn is_expired(&self) -> bool {
        self.expires_at
            .map(|expires| Instant::now() > expires)
            .unwrap_or(false)
    }

    fn touch(&mut self) {
        self.access_count += 1;
    }
}

// LRU tracking structure
#[derive(Debug)]
struct LruTracker<K> {
    order: Vec<K>,
    positions: HashMap<K, usize>,
}

impl<K: Clone + Hash + Eq> LruTracker<K> {
    fn new() -> Self {
        Self {
            order: Vec::new(),
            positions: HashMap::new(),
        }
    }

    fn touch(&mut self, key: &K) {
        if let Some(&pos) = self.positions.get(key) {
            // Move to front
            let key = self.order.remove(pos);
            self.order.insert(0, key);
            self.rebuild_positions();
        } else {
            // Add new key to front
            self.order.insert(0, key.clone());
            self.rebuild_positions();
        }
    }

    fn remove(&mut self, key: &K) {
        if let Some(&pos) = self.positions.get(key) {
            self.order.remove(pos);
            self.positions.remove(key);
            self.rebuild_positions();
        }
    }

    fn get_lru(&self) -> Option<&K> {
        self.order.last()
    }

    fn len(&self) -> usize {
        self.order.len()
    }

    fn rebuild_positions(&mut self) {
        self.positions.clear();
        for (index, key) in self.order.iter().enumerate() {
            self.positions.insert(key.clone(), index);
        }
    }
}

