**Document Sharding Strategy:**
```go
type DocumentShard struct {
    ShardID    int
    NodeID     string
    Documents  map[string]*Document
    LoadFactor float64
}

func (s *ShardManager) GetShardForDocument(docID string) int {
    // Consistent hashing for even distribution
    hash := crc32.ChecksumIEEE([]byte(docID))
    return int(hash % uint32(s.shardCount))
}

func (s *ShardManager) RebalanceShards() {
    // Monitor load and migrate documents between shards
    for _, shard := range s.shards {
        if shard.LoadFactor > 0.8 {
            s.migrateDocuments(shard)
        }
    }
}
