  }

  ingress {
    description     = "HTTPS from CloudFront"
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    prefix_list_ids = [var.cloudfront_prefix_list_id]
  }

  egress {
    description = "All outbound traffic to ECS"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
