data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Base IAM Policy Documents for Layered Composition
data "aws_iam_policy_document" "base_ecs_task" {
  statement {
    sid       = "BaseRegionRestriction"
    effect    = "Allow"
    actions   = ["sts:AssumeRole"]
    resources = ["*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }
}

data "aws_iam_policy_document" "base_secrets_access" {
  statement {
    sid    = "BaseSecretsAccess"
    effect = "Allow"
    actions = [
      "secretsmanager:GetSecretValue"
    ]
    resources = ["arn:aws:secretsmanager:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:secret:${var.project_name}/${var.environment}/*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }
}

# ECS Task Execution Role - for pulling images and logging
resource "aws_iam_role" "ecs_execution_role" {
  name                 = "${var.project_name}-${var.environment}-ecs-execution-role"
  max_session_duration = 3600

  assume_role_policy = data.aws_iam_policy_document.ecs_assume_role.json

  tags = var.tags
}

data "aws_iam_policy_document" "ecs_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["ecs-tasks.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }
}

data "aws_iam_policy_document" "ecs_execution" {
  source_policy_documents = [data.aws_iam_policy_document.base_ecs_task.json]

  statement {
    sid    = "ECRRegistryAccess"
    effect = "Allow"
    actions = [
      "ecr:GetAuthorizationToken"
    ]
    resources = ["*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }

  statement {
    sid    = "ECRRepositoryAccess"
    effect = "Allow"
    actions = [
      "ecr:BatchCheckLayerAvailability",
      "ecr:GetDownloadUrlForLayer",
      "ecr:BatchGetImage"
    ]
    resources = ["arn:aws:ecr:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:repository/${var.project_name}-*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }

  statement {
    sid    = "CloudWatchLogsAccess"
    effect = "Allow"
    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "logs:DescribeLogStreams"
    ]
    resources = ["arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/ecs/${var.project_name}-${var.environment}-*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }
}

data "aws_iam_policy_document" "ecs_execution_secrets" {
  source_policy_documents = [data.aws_iam_policy_document.base_secrets_access.json]

  statement {
    sid    = "SecretsManagerTaskExecution"
    effect = "Allow"
    actions = [
      "secretsmanager:GetSecretValue"
    ]
    resources = ["arn:aws:secretsmanager:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:secret:${var.project_name}/${var.environment}/*"]

    condition {
      test     = "StringEquals"
      variable = "aws:RequestedRegion"
      values   = [data.aws_region.current.name]
    }
  }
}

resource "aws_iam_policy" "ecs_execution_policy" {
  name        = "${var.project_name}-${var.environment}-ecs-execution-policy"
  description = "Least privilege policy for ECS task execution"

  policy = data.aws_iam_policy_document.ecs_execution.json

  tags = var.tags
}

resource "aws_iam_policy" "ecs_execution_secrets_policy" {
  name        = "${var.project_name}-${var.environment}-ecs-execution-secrets-policy"
  description = "Secrets access policy for ECS task execution"

  policy = data.aws_iam_policy_document.ecs_execution_secrets.json

